<main class="container-fluid px-3 px-lg-4 py-4"><?php if($this->session->flashdata('success')): ?><div class="alert alert-success border-0 shadow-sm"><?= $this->session->flashdata('success'); ?></div><?php endif; ?><?php if($this->session->flashdata('error')): ?><div class="alert alert-danger border-0 shadow-sm"><?= $this->session->flashdata('error'); ?></div><?php endif; ?><div class="row g-4"><div class="col-lg-4"><div class="panel-card p-3 p-lg-4"><h5 class="fw-bold mb-3">Catat Distribusi</h5><form action="<?= base_url('index.php/admin/distribusi/simpan') ?>" method="post" class="vstack gap-3"><div><label class="form-label small fw-semibold text-muted">Aset</label><select name="id_aset" class="form-select" required><option value="">Pilih aset</option><?php foreach($aset as $a): ?><option value="<?= $a->id_aset ?>"><?= html_escape($a->nama_aset.' - '.$a->kode_aset.' ('.$a->nama_ruangan.')') ?></option><?php endforeach; ?></select></div><div><label class="form-label small fw-semibold text-muted">Ruangan Tujuan</label><select name="id_ruangan_tujuan" class="form-select" required><option value="">Pilih ruangan</option><?php foreach($ruangan as $r): ?><option value="<?= $r['id_ruangan'] ?>"><?= html_escape($r['nama_ruangan']) ?></option><?php endforeach; ?></select></div><div class="row g-2"><div class="col-6"><label class="form-label small fw-semibold text-muted">Jumlah</label><input type="number" name="jumlah" min="1" value="1" class="form-control"></div><div class="col-6"><label class="form-label small fw-semibold text-muted">Tanggal</label><input type="date" name="tanggal_distribusi" value="<?= date('Y-m-d') ?>" class="form-control"></div></div><div><label class="form-label small fw-semibold text-muted">Keterangan</label><textarea name="keterangan" class="form-control" rows="3"></textarea></div><button class="btn btn-fik rounded-pill"><i class="bi bi-arrow-left-right me-1"></i> Simpan Distribusi</button></form></div></div><div class="col-lg-8"><div class="panel-card p-0 overflow-hidden"><div class="table-responsive"><table class="table table-hover mb-0"><thead><tr><th class="ps-3">Aset</th><th>Perpindahan</th><th>Jumlah</th><th>Tanggal</th><th>Petugas</th></tr></thead><tbody><?php if(empty($distribusi)): ?><tr><td colspan="5" class="text-center text-muted py-5">Belum ada riwayat distribusi.</td></tr><?php else: foreach($distribusi as $d): ?><tr><td class="ps-3"><div class="fw-semibold"><?= html_escape($d->nama_aset) ?></div><div class="small text-muted"><?= html_escape($d->kode_aset) ?></div></td><td><div><?= html_escape($d->ruangan_asal ?: '-') ?> <i class="bi bi-arrow-right mx-1 text-muted"></i> <?= html_escape($d->ruangan_tujuan ?: '-') ?></div><div class="small text-muted"><?= html_escape($d->keterangan ?: '') ?></div></td><td><?= (int)$d->jumlah ?></td><td><?= html_escape($d->tanggal_distribusi) ?></td><td><?= html_escape($d->nama_petugas ?: 'Laboran') ?></td></tr><?php endforeach; endif; ?></tbody></table></div></div></div></div></main><script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script></body></html>